const items = $input.all();
const sevenDaysAgo = new Date();
sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);

const filtered = items.filter(function(item) {
  const d = new Date(item.json.isoDate || item.json.pubDate || '');
  return !isNaN(d) && d >= sevenDaysAgo;
});

if (filtered.length === 0) throw new Error('Nessun articolo negli ultimi 7 giorni. Controlla i feed o allarga la finestra nel codice.');

const sorted = filtered
  .sort(function(a, b) {
    return new Date(b.json.isoDate || b.json.pubDate) - new Date(a.json.isoDate || a.json.pubDate);
  })
  .slice(0, 20);

return sorted.map(function(item) {
  var hostname;
  try { hostname = new URL(item.json.link).hostname; } catch(e) { hostname = ''; }
  return {
    json: {
      titolo: item.json.title || '',
      link: item.json.link || '',
      fonte: hostname,
      data: new Date(item.json.isoDate || item.json.pubDate).toLocaleDateString('it-IT'),
      snippet: String(item.json.contentSnippet || item.json.content || '').replace(/<[^>]*>/g, '').slice(0, 300)
    }
  };
});

const text = $input.first().json.content[0].text.trim();

const m = text.match(/\{[\s\S]*\}/);
if (!m) throw new Error('Nessun JSON trovato: ' + text.slice(0, 200));

let d;
try { d = JSON.parse(m[0]); }
catch(e) { throw new Error('JSON non parsabile'); }

const oggi = new Date().toLocaleDateString('it-IT', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

const articoliHtml = d.articoli.map(function(a) {
  return '<div style="margin-bottom:24px;padding-bottom:24px;border-bottom:1px solid #e8e8e8">'
    + '<p style="font-size:11px;color:#888;margin:0 0 4px;font-family:sans-serif"><strong>' + a.tag + '</strong> &middot; ' + a.fonte + '</p>'
    + '<h2 style="margin:0 0 8px;font-size:18px;line-height:1.3"><a href="' + a.link + '" style="color:#111;text-decoration:none">' + a.titolo_editoriale + '</a></h2>'
    + '<p style="margin:0 0 10px;color:#444;font-size:14px;line-height:1.7">' + a.riassunto + '</p>'
    + '<a href="' + a.link + '" style="font-size:13px;color:#0055cc;font-family:sans-serif">Leggi &rarr;</a>'
    + '</div>';
}).join('');

const html = '<!DOCTYPE html><html lang="it"><body style="font-family:Georgia,serif;max-width:620px;margin:0 auto;padding:28px 24px;color:#111">'
  + '<p style="color:#999;font-size:12px;margin:0 0 6px;font-family:sans-serif;text-transform:uppercase;letter-spacing:1px">Digest settimanale &middot; ' + oggi + '</p>'
  + '<h1 style="font-size:26px;margin:0 0 18px;line-height:1.3">' + d.titolo_newsletter + '</h1>'
  + '<p style="font-size:15px;line-height:1.75;color:#333;border-left:3px solid #0055cc;padding:2px 0 2px 14px;margin:0 0 28px">' + d.intro + '</p>'
  + '<hr style="border:none;border-top:1px solid #e8e8e8;margin:0 0 28px">'
  + articoliHtml
  + '<p style="font-size:14px;color:#666;font-style:italic;margin:28px 0 0">' + d.chiusura + '</p>'
  + '<hr style="border:none;border-top:1px solid #e8e8e8;margin:24px 0 14px">'
  + '<p style="font-size:11px;color:#bbb;font-family:sans-serif;margin:0">Generato automaticamente &middot; n8n + Claude Sonnet</p>'
  + '</body></html>';

return [{ json: { subject: d.titolo_newsletter, html: html } }];
